import { useState, useEffect, useRef } from "react";
import { useAuth } from "../context/AuthContext";
import API from "../services/api";
import socket from "../services/socket";
import Sidebar from "../components/Sidebar";
import ChatWindow from "../components/ChatWindow";
import StatusBar from "../components/StatusBar";
import ProfileModal from "../components/ProfileModal";
import UserProfileModal from "../components/UserProfileModal";
import "./Chat.css";

export default function Chat() {
  const { user, logout, updateUser } = useAuth();
  const [friends, setFriends] = useState([]);
  const [selectedFriend, setSelectedFriend] = useState(null);
  const [messages, setMessages] = useState([]);
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [typingUser, setTypingUser] = useState(null);
  const [text, setText] = useState("");
  const [showMyProfile, setShowMyProfile] = useState(false);
  const [showUserProfile, setShowUserProfile] = useState(false);
  const [canMsg, setCanMsg] = useState({ canMessage: true, mutualFollow: false, msgCount: 0 });
  const [msgError, setMsgError] = useState("");
  const [mediaPreview, setMediaPreview] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [replyTo, setReplyTo] = useState(null);
  const [forwardMsg, setForwardMsg] = useState(null);
  const [showSchedule, setShowSchedule] = useState(false);
  const [scheduleTime, setScheduleTime] = useState("");
  const [recording, setRecording] = useState(false);
  const [audioBlob, setAudioBlob] = useState(null);
  const [showForwardPicker, setShowForwardPicker] = useState(false);

  const typingTimer = useRef(null);
  const selectedFriendRef = useRef(selectedFriend);
  const mediaRef = useRef();
  const mediaRecorderRef = useRef();
  const audioChunks = useRef([]);

  useEffect(() => { selectedFriendRef.current = selectedFriend; }, [selectedFriend]);

  useEffect(() => {
    socket.connect();
    socket.emit("userOnline", user.username);
    socket.on("onlineUsers", setOnlineUsers);

    socket.on("receiveMessage", (msg) => {
      const sf = selectedFriendRef.current;
      if (sf && (msg.sender === sf.username || msg.receiver === sf.username)) {
        setMessages(prev => [...prev, msg]);
        socket.emit("messageSeen", msg._id);
      }
    });

    socket.on("messageSent", (msg) => {
      setMessages(prev => [...prev, msg]);
    });

    socket.on("messageStatus", ({ messageId, status }) => {
      setMessages(prev => prev.map(m => m._id === messageId ? { ...m, status } : m));
    });

    socket.on("allMessagesSeen", ({ from }) => {
      const sf = selectedFriendRef.current;
      if (sf && sf.username === from) {
        setMessages(prev => prev.map(m => ({ ...m, status: "seen" })));
      }
    });

    socket.on("typing", (sender) => {
      if (selectedFriendRef.current?.username === sender) setTypingUser(sender);
    });
    socket.on("stopTyping", () => setTypingUser(null));

    socket.on("messageError", ({ message }) => {
      setMsgError(message);
      setTimeout(() => setMsgError(""), 4000);
    });

    socket.on("editError", ({ message }) => {
      setMsgError(message);
      setTimeout(() => setMsgError(""), 3000);
    });

    return () => {
      socket.off("onlineUsers"); socket.off("receiveMessage");
      socket.off("messageSent"); socket.off("messageStatus");
      socket.off("allMessagesSeen"); socket.off("typing");
      socket.off("stopTyping"); socket.off("messageError"); socket.off("editError");
      socket.disconnect();
    };
  }, []);

  useEffect(() => {
    API.get("/users").then(res => setFriends(res.data)).catch(console.log);
  }, []);

  useEffect(() => {
    if (!selectedFriend) return;
    API.get(`/messages/${selectedFriend.username}`)
      .then(res => {
        setMessages(res.data);
        socket.emit("markAllSeen", { sender: selectedFriend.username, receiver: user.username });
      }).catch(console.log);
    API.get(`/messages/${selectedFriend.username}/can`)
      .then(res => setCanMsg(res.data))
      .catch(console.log);
  }, [selectedFriend]);

  const handleSend = (isScheduled = false) => {
    if ((!text.trim() && !mediaPreview && !audioBlob) || !selectedFriend) return;
    if (!canMsg.canMessage) {
      setMsgError("You can only send 1 message until they follow you back");
      return;
    }

    const msgData = {
      sender: user.username,
      receiver: selectedFriend.username,
      text: text.trim(),
      mediaUrl: mediaPreview?.url || "",
      mediaType: mediaPreview?.type || "",
      replyTo: replyTo ? {
        messageId: replyTo._id,
        text: replyTo.text,
        sender: replyTo.sender,
        mediaType: replyTo.mediaType,
      } : null,
    };

    if (isScheduled && scheduleTime) {
      API.post("/messages/schedule", { ...msgData, scheduledAt: scheduleTime })
        .then(() => {
          setMsgError("✅ Message scheduled!");
          setTimeout(() => setMsgError(""), 3000);
        }).catch(console.log);
      setShowSchedule(false);
      setScheduleTime("");
    } else {
      socket.emit("sendMessage", msgData);
    }

    setText("");
    setMediaPreview(null);
    setAudioBlob(null);
    setReplyTo(null);
    socket.emit("stopTyping", { receiver: selectedFriend.username });
  };

  const handleKey = (e) => {
    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleSend(); }
  };

  const handleTyping = () => {
    socket.emit("typing", { receiver: selectedFriend?.username, sender: user.username });
    clearTimeout(typingTimer.current);
    typingTimer.current = setTimeout(() => {
      socket.emit("stopTyping", { receiver: selectedFriend?.username });
    }, 1500);
  };

  const handleMediaSelect = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setUploading(true);
    const fd = new FormData();
    fd.append("media", file);
    try {
      const res = await API.post("/users/me/media", fd);
      setMediaPreview({ url: res.data.mediaUrl, type: res.data.mediaType });
    } catch (err) { console.log(err); }
    setUploading(false);
  };

  // Voice recording
  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorderRef.current = new MediaRecorder(stream);
      audioChunks.current = [];
      mediaRecorderRef.current.ondataavailable = e => audioChunks.current.push(e.data);
      mediaRecorderRef.current.onstop = async () => {
        const blob = new Blob(audioChunks.current, { type: "audio/webm" });
        const fd = new FormData();
        fd.append("media", blob, "voice.webm");
        try {
          const res = await API.post("/users/me/media", fd);
          socket.emit("sendMessage", {
            sender: user.username,
            receiver: selectedFriend.username,
            text: "",
            mediaUrl: res.data.mediaUrl,
            mediaType: "audio",
          });
        } catch (err) { console.log(err); }
        stream.getTracks().forEach(t => t.stop());
      };
      mediaRecorderRef.current.start();
      setRecording(true);
    } catch (err) { console.log("Mic error:", err); }
  };

  const stopRecording = () => {
    mediaRecorderRef.current?.stop();
    setRecording(false);
  };

  // Forward message
  const handleForwardTo = (friend) => {
    if (!forwardMsg) return;
    socket.emit("sendMessage", {
      sender: user.username,
      receiver: friend.username,
      text: forwardMsg.text,
      mediaUrl: forwardMsg.mediaUrl || "",
      mediaType: forwardMsg.mediaType || "",
      isForwarded: true,
    });
    setForwardMsg(null);
    setShowForwardPicker(false);
    setMsgError(`✅ Forwarded to @${friend.username}`);
    setTimeout(() => setMsgError(""), 3000);
  };

  const isOnline = onlineUsers.includes(selectedFriend?.username);
  const isLimited = !canMsg.mutualFollow && canMsg.msgCount >= 1;

  return (
    <div className="chat-page">
      <Sidebar
        currentUser={user}
        friends={friends}
        selectedFriend={selectedFriend}
        onSelectFriend={setSelectedFriend}
        onlineUsers={onlineUsers}
        onLogout={logout}
        onOpenProfile={() => setShowMyProfile(true)}
        messages={messages}
        typingUser={typingUser}
      />

      <div className="chat-main">
        <StatusBar currentUser={user} />

        {selectedFriend ? (
          <>
            {/* Header */}
            <div className="chat-header" onClick={() => setShowUserProfile(true)}>
              <div className="chat-header-left">
                <div className="header-avatar">
                  {selectedFriend.profilePic
                    ? <img src={selectedFriend.profilePic} alt="" />
                    : selectedFriend.username[0].toUpperCase()
                  }
                </div>
                <div className="header-info">
                  <span className="header-name">{selectedFriend.username}</span>
                  <span className={`header-status ${isOnline ? "online" : ""}`}>
                    <span className="status-dot-sm" />
                    {typingUser ? "typing..." : isOnline ? "Active now" : "Offline"}
                  </span>
                </div>
              </div>
              <div className="header-actions" onClick={e => e.stopPropagation()}>
                <button className="icon-btn" onClick={() => setShowUserProfile(true)}>👤</button>
              </div>
            </div>

            {isLimited && (
              <div className="msg-limit-banner">
                🔒 You can only send 1 message until <strong>@{selectedFriend.username}</strong> follows you back
              </div>
            )}

            <ChatWindow
              messages={messages}
              setMessages={setMessages}
              currentUser={user}
              selectedFriend={selectedFriend}
              typingUser={typingUser}
              onReply={(msg) => setReplyTo(msg)}
              onForward={(msg) => { setForwardMsg(msg); setShowForwardPicker(true); }}
            />

            {/* Reply preview bar */}
            {replyTo && (
              <div className="reply-bar">
                <div className="reply-bar-content">
                  <span className="reply-bar-label">↩ Replying to @{replyTo.sender}</span>
                  <span className="reply-bar-text">{replyTo.text || "📎 Media"}</span>
                </div>
                <button className="reply-bar-close" onClick={() => setReplyTo(null)}>✕</button>
              </div>
            )}

            {/* Media preview */}
            {mediaPreview && (
              <div className="media-preview-bar">
                {mediaPreview.type === "video"
                  ? <video src={mediaPreview.url} className="media-preview-thumb" />
                  : <img src={mediaPreview.url} alt="" className="media-preview-thumb" />
                }
                <button className="media-preview-remove" onClick={() => setMediaPreview(null)}>✕</button>
              </div>
            )}

            {/* Schedule picker */}
            {showSchedule && (
              <div className="schedule-bar">
                <span className="schedule-label">🕐 Schedule for:</span>
                <input
                  type="datetime-local"
                  className="schedule-input"
                  value={scheduleTime}
                  onChange={e => setScheduleTime(e.target.value)}
                  min={new Date().toISOString().slice(0,16)}
                />
                <button className="schedule-send" onClick={() => handleSend(true)} disabled={!scheduleTime}>Schedule</button>
                <button className="schedule-cancel" onClick={() => setShowSchedule(false)}>✕</button>
              </div>
            )}

            {msgError && <div className={`msg-error-bar ${msgError.startsWith("✅") ? "success" : ""}`}>{msgError}</div>}

            {/* Input bar */}
            <div className="input-bar">
              <input ref={mediaRef} type="file" accept="image/*,video/*" hidden onChange={handleMediaSelect} />

              <button className="attach-btn" onClick={() => mediaRef.current.click()} disabled={uploading} title="Attach media">
                {uploading ? "⏳" : "📎"}
              </button>

              {/* Voice record button */}
              <button
                className={`voice-btn ${recording ? "recording" : ""}`}
                onMouseDown={startRecording}
                onMouseUp={stopRecording}
                onTouchStart={startRecording}
                onTouchEnd={stopRecording}
                title="Hold to record voice message"
              >
                {recording ? "🔴" : "🎤"}
              </button>

              <textarea
                className="msg-input"
                placeholder={isLimited ? "Follow each other to chat freely..." : `Message @${selectedFriend.username}...`}
                value={text}
                onChange={e => { setText(e.target.value); handleTyping(); }}
                onKeyDown={handleKey}
                rows={1}
                disabled={isLimited}
              />

              {/* Schedule button */}
              <button className="icon-btn schedule-btn" onClick={() => setShowSchedule(!showSchedule)} title="Schedule message">
                🕐
              </button>

              <button
                className={`send-btn ${(text.trim() || mediaPreview) && !isLimited ? "active" : ""}`}
                onClick={() => handleSend()}
                disabled={(!text.trim() && !mediaPreview) || isLimited}
              >
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2">
                  <line x1="22" y1="2" x2="11" y2="13"/>
                  <polygon points="22 2 15 22 11 13 2 9 22 2"/>
                </svg>
              </button>
            </div>
          </>
        ) : (
          <div className="empty-state">
            <div className="empty-icon">💬</div>
            <h2>Select a conversation</h2>
            <p>Pick someone from the sidebar to start chatting</p>
          </div>
        )}
      </div>

      {/* Forward picker */}
      {showForwardPicker && (
        <div className="modal-overlay" onClick={() => setShowForwardPicker(false)}>
          <div className="forward-modal" onClick={e => e.stopPropagation()}>
            <h3 className="forward-title">↪ Forward to...</h3>
            <div className="forward-list">
              {friends.map(f => (
                <div key={f._id} className="forward-item" onClick={() => handleForwardTo(f)}>
                  <div className="pm-user-av">
                    {f.profilePic ? <img src={f.profilePic} alt="" /> : f.username[0].toUpperCase()}
                  </div>
                  <span className="pm-user-name">@{f.username}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {showMyProfile && (
        <ProfileModal currentUser={user} onClose={() => setShowMyProfile(false)} onProfileUpdate={updateUser} />
      )}

      {showUserProfile && selectedFriend && (
        <UserProfileModal targetUsername={selectedFriend.username} currentUser={user} onClose={() => setShowUserProfile(false)} />
      )}
    </div>
  );
}
